#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

__kernel void pgain_kernel(
    __global const Point_Struct *p,
    __global const float *coord,
    __global float *work_mem,
    __global const int *center_table,
    __global char *switch_membership,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = (int)p[i].assign;
        int ct = center_table[assign];
        if (ct >= 0 && ct < K) {
            work_mem[i * (K + 1) + ct] += current_cost - x_cost;
        }
    }
}
